"""
Step ID: step05
Step Name: group_comparisons_anova
RQ: results/ch7/7.7.2
Generated: 2026-01-09

PURPOSE:
Compare three groups (VR-favored, RAVLT-favored, Concordant) on demographic variables
using one-way ANOVA with post-hoc Tukey HSD. Report dual p-values per Decision D068.

EXPECTED INPUTS:
  - results/ch7/7.7.2/data/step04_demographic_data.csv

EXPECTED OUTPUTS:
  - results/ch7/7.7.2/data/step05_anova_results.csv
    (Columns: variable, F_stat, df1, df2, p_uncorrected, p_bonferroni, eta_squared)
  - results/ch7/7.7.2/data/step05_posthoc_comparisons.csv
  - results/ch7/7.7.2/data/step05_assumption_checks.csv
  - results/ch7/7.7.2/data/step05_power_analysis.csv

g_code REASONING:
- Run one-way ANOVA per demographic variable
- Bonferroni correction: alpha=0.05/9=0.0056 (3 variables × 3 pairwise comparisons)
- Report both uncorrected and corrected p-values (Decision D068)
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from scipy import stats as scipy_stats
from statsmodels.stats.multitest import multipletests
from statsmodels.stats.power import FTestAnovaPower
import traceback

PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

from tools.analysis_stats import one_way_anova_d068
from tools.validation import validate_hypothesis_test_dual_pvalues

RQ_DIR = Path(__file__).resolve().parents[1]
LOG_FILE = RQ_DIR / "logs" / "step05_group_comparisons_anova.log"

def log(msg):
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

if __name__ == "__main__":
    try:
        log("[START] Step 05: Group Comparisons ANOVA")

        # Load demographic data
        log("[LOAD] Loading demographic data...")
        df = pd.read_csv(RQ_DIR / "data" / "step04_demographic_data.csv")
        log(f"[LOADED] {len(df)} participants")

        # Identify demographic variables (exclude UID, Group*, Discrepancy*)
        exclude_cols = ['UID'] + [c for c in df.columns if c.startswith('Group') or c.startswith('Discrepancy')]
        demo_vars = [col for col in df.columns if col not in exclude_cols]
        log(f"[INFO] Demographic variables for ANOVA: {demo_vars}")

        # Identify grouping columns to iterate over
        grouping_schemes = {
            'RAVLT_Total': 'Group_RAVLT_Total' if 'Group_RAVLT_Total' in df.columns else 'Group',
            'RAVLT_Pct_Ret': 'Group_RAVLT_Pct_Ret'
        }
        # Filter to available columns
        grouping_schemes = {k: v for k, v in grouping_schemes.items() if v in df.columns}

        log(f"[INFO] Grouping schemes: {grouping_schemes}")

        # ANOVA for each variable x grouping scheme
        log("[ANOVA] Running one-way ANOVA for each demographic variable and grouping scheme...")

        anova_results = []
        posthoc_results = []
        assumption_results = []

        for scheme_label, group_col in grouping_schemes.items():
            log(f"\n[ANOVA] === {scheme_label} (column: {group_col}) ===")

            n_comparisons = len(demo_vars) * 3  # variables × 3 pairwise comparisons
            alpha_bonferroni = 0.05 / n_comparisons
            log(f"[INFO] Bonferroni correction: alpha = 0.05/{n_comparisons} = {alpha_bonferroni:.4f}")

            for var in demo_vars:
                # Remove missing values
                df_complete = df[[group_col, var]].dropna()
                df_complete = df_complete.rename(columns={group_col: 'Group'})

                if len(df_complete) < len(df):
                    log(f"[WARNING] {var}: {len(df) - len(df_complete)} participants excluded due to missing data")

                # Run one-way ANOVA using D068 function
                result = one_way_anova_d068(
                    data=df_complete,
                    dv=var,
                    between='Group',
                    correction='bonferroni',
                    n_comparisons=n_comparisons
                )

                # Extract ANOVA results
                anova_results.append({
                    'metric': scheme_label,
                    'variable': var,
                    'F_stat': result.get('F', np.nan),
                    'df1': result.get('df_between', np.nan),
                    'df2': result.get('df_within', np.nan),
                    'p_uncorrected': result.get('p_uncorrected', np.nan),
                    'p_bonferroni': result.get('p_corrected', np.nan),
                    'eta_squared': result.get('eta_squared', np.nan)
                })

                log(f"[ANOVA] {scheme_label}/{var}: F({result.get('df_between', '?')},{result.get('df_within', '?')})={result.get('F', np.nan):.3f}, p_uncorr={result.get('p_uncorrected', np.nan):.4f}, p_bonf={result.get('p_corrected', np.nan):.4f}")

                # Post-hoc comparisons (if ANOVA significant)
                if result.get('posthoc') is not None:
                    posthoc_df_tmp = result['posthoc'].copy()
                    posthoc_df_tmp['metric'] = scheme_label
                    posthoc_df_tmp['variable'] = var
                    posthoc_results.append(posthoc_df_tmp)

                # Assumption checks
                groups = [df_complete[df_complete['Group'] == g][var].values for g in df_complete['Group'].unique()]
                levene_stat, levene_p = scipy_stats.levene(*groups)

                for group_name in df_complete['Group'].unique():
                    group_data = df_complete[df_complete['Group'] == group_name][var].values
                    if len(group_data) >= 3:
                        shapiro_stat, shapiro_p = scipy_stats.shapiro(group_data)
                        assumption_results.append({
                            'metric': scheme_label,
                            'variable': var,
                            'group': group_name,
                            'n': len(group_data),
                            'shapiro_W': shapiro_stat,
                            'shapiro_p': shapiro_p,
                            'levene_F': levene_stat,
                            'levene_p': levene_p
                        })

        # Combine results
        anova_df = pd.DataFrame(anova_results)
        posthoc_df = pd.concat(posthoc_results, ignore_index=True) if posthoc_results else pd.DataFrame()
        assumption_df = pd.DataFrame(assumption_results)

        # Power analysis
        log("[POWER] Computing post-hoc power analysis...")
        power_results = []
        power_test = FTestAnovaPower()

        for _, row in anova_df.iterrows():
            if not pd.isna(row['F_stat']) and not pd.isna(row['eta_squared']):
                # Convert eta^2 to f^2
                f2 = row['eta_squared'] / (1 - row['eta_squared'])
                n = row['df1'] + row['df2'] + 1

                # Compute observed power
                power = power_test.solve_power(
                    effect_size=f2,
                    nobs=n,
                    alpha=0.05
                )

                power_results.append({
                    'metric': row.get('metric', 'RAVLT_Total'),
                    'variable': row['variable'],
                    'f2': f2,
                    'power': power,
                    'n': n
                })

        power_df = pd.DataFrame(power_results)

        # Save outputs
        log("[SAVE] Saving ANOVA results...")

        output_anova = RQ_DIR / "data" / "step05_anova_results.csv"
        anova_df.to_csv(output_anova, index=False, encoding='utf-8')
        log(f"[SAVED] {output_anova.name} ({len(anova_df)} rows)")

        if not posthoc_df.empty:
            output_posthoc = RQ_DIR / "data" / "step05_posthoc_comparisons.csv"
            posthoc_df.to_csv(output_posthoc, index=False, encoding='utf-8')
            log(f"[SAVED] {output_posthoc.name} ({len(posthoc_df)} rows)")
        else:
            log("[INFO] No significant ANOVA results - no post-hoc comparisons")

        output_assumptions = RQ_DIR / "data" / "step05_assumption_checks.csv"
        assumption_df.to_csv(output_assumptions, index=False, encoding='utf-8')
        log(f"[SAVED] {output_assumptions.name} ({len(assumption_df)} rows)")

        output_power = RQ_DIR / "data" / "step05_power_analysis.csv"
        power_df.to_csv(output_power, index=False, encoding='utf-8')
        log(f"[SAVED] {output_power.name} ({len(power_df)} rows)")

        # Validation - check dual p-values manually since validator has different signature
        log("[VALIDATION] Checking dual p-value reporting...")

        # Check p-values are present and valid
        if 'p_uncorrected' in anova_df.columns and 'p_bonferroni' in anova_df.columns:
            # Check all p-values in [0, 1]
            p_uncorr_valid = anova_df['p_uncorrected'].between(0, 1, inclusive='both').all()
            p_bonf_valid = anova_df['p_bonferroni'].between(0, 1, inclusive='both').all()

            # Check corrected >= uncorrected
            p_order_valid = (anova_df['p_bonferroni'] >= anova_df['p_uncorrected']).all()

            if p_uncorr_valid and p_bonf_valid and p_order_valid:
                log("[PASS] Dual p-value reporting validated")
            else:
                log(f"[WARNING] P-value validation issues detected")
        else:
            log(f"[WARNING] Missing p-value columns")

        log("[SUCCESS] Step 05 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
